//! ackermann-bench — runtime certification harness for the Ackermann
//! ceiling protocol. See `ACKERMANN_CERTIFICATION_PROTOCOL.md`.
//!
//! Wraps a small library of hardcoded target functions (constant,
//! identity, polynomial, exponential, naive-ackermann, memoized-
//! ackermann), instruments their step counts, runs each through
//! `crate::ackermann_certificate::certify`, and emits one JSON-line
//! per (target, n) with `(steps, ceiling, percentile)`.
//!
//! For `n >= 4` the Ackermann ceiling is too large to fit into u64, so
//! we drop to a structural-fallback regime: emit `structural: true` and
//! a `polynomial_degree_estimate` (or `null` when growth is super-
//! polynomial). Per CLAUDE.md, the fallback is flagged in-band on every
//! such line — no silent degradation.
//!
//! ## CLI
//!
//! ```text
//! ackermann-bench [--target NAME[,NAME...]] [--max-n N] [--report json]
//! ```
//!
//! Defaults:
//!   --target constant,identity,quadratic,cubic,exponential,naive-ackermann,memoized-ackermann
//!   --max-n 3
//!   --report json
//!
//! Mirrors `src/bin/bowl-q-sweep.rs` in CLI parsing + JSON-emit style.
//! NOTE: requires a `[[bin]] ackermann-bench` entry in Cargo.toml. This
//! binary does NOT add that itself — register it in Cargo.toml manually.

use std::env;
use std::io::{self, Write};

use distributed_inference::ackermann_certificate::{
    certify, polynomial_degree_estimate, AckermannCertificate,
};

#[derive(Clone, Copy, Debug)]
enum Target {
    Constant,
    Identity,
    Quadratic,
    Cubic,
    Exponential,
    NaiveAckermann,
    MemoizedAckermann,
}

impl Target {
    fn name(self) -> &'static str {
        match self {
            Target::Constant => "constant",
            Target::Identity => "identity",
            Target::Quadratic => "quadratic",
            Target::Cubic => "cubic",
            Target::Exponential => "exponential",
            Target::NaiveAckermann => "naive-ackermann",
            Target::MemoizedAckermann => "memoized-ackermann",
        }
    }

    fn parse(s: &str) -> Result<Self, String> {
        match s.trim() {
            "constant" => Ok(Target::Constant),
            "identity" => Ok(Target::Identity),
            "quadratic" => Ok(Target::Quadratic),
            "cubic" => Ok(Target::Cubic),
            "exponential" => Ok(Target::Exponential),
            "naive-ackermann" => Ok(Target::NaiveAckermann),
            "memoized-ackermann" => Ok(Target::MemoizedAckermann),
            other => Err(format!("unknown target {:?}", other)),
        }
    }

    /// Step count for the target at input `n`.
    ///
    /// "Step" semantics is target-specific and matches the contract in
    /// the module doc. Counters are saturating in u64 — Ackermann growth
    /// blows past 2^64 fast and we'd rather emit a saturated value than
    /// panic on overflow inside the harness.
    fn evaluate(self, n: u32) -> u64 {
        match self {
            // constant: one step regardless of n
            Target::Constant => 1,

            // identity: n steps
            Target::Identity => n as u64,

            // quadratic: n*n steps
            Target::Quadratic => {
                let nn = n as u64;
                nn.saturating_mul(nn)
            }

            // cubic: n*n*n steps
            Target::Cubic => {
                let nn = n as u64;
                nn.saturating_mul(nn).saturating_mul(nn)
            }

            // exponential: 2^n steps (saturating)
            Target::Exponential => {
                if n >= 63 {
                    u64::MAX
                } else {
                    1u64 << n
                }
            }

            // naive_ackermann: number of recursive hyperop calls to
            // reach the value, mirroring the Lean hyperop definition.
            // For n=0 we report 1 (the base call itself). For n>=4 the
            // recursion is astronomical; the harness only invokes this
            // path for n in [0,3] (the numeric range) — callers for
            // n>=4 should use the structural-fallback regime.
            Target::NaiveAckermann => naive_ackermann_steps(n),

            // memoized_ackermann: with a memo table built once, the
            // number of distinct (a,b) pairs visited is polynomial in
            // n. We return that count as the step proxy.
            Target::MemoizedAckermann => memoized_ackermann_steps(n),
        }
    }
}

/// Counted naive hyperop / Ackermann-style recursion.
///
/// We use the standard two-arg Ackermann:
///   A(0, n)         = n + 1
///   A(m, 0)         = A(m-1, 1)
///   A(m, n)         = A(m-1, A(m, n))
///
/// The "step count" is the total number of function invocations made
/// to evaluate `A(n, n)`. Guarded with a saturating counter and an
/// explicit `n <= 3` precondition so we don't accidentally launch a
/// many-hour recursion if a caller wires us up wrong.
fn naive_ackermann_steps(n: u32) -> u64 {
    if n > 3 {
        // Defensive guard. The harness should be using the structural
        // fallback for n >= 4. Saturate rather than panic so a misuse
        // shows up as a wire-level MAX value, not a SIGABRT.
        return u64::MAX;
    }
    let mut counter: u64 = 0;
    ack_count(n, n, &mut counter);
    counter
}

fn ack_count(m: u32, n: u32, counter: &mut u64) -> u32 {
    *counter = counter.saturating_add(1);
    if m == 0 {
        n.saturating_add(1)
    } else if n == 0 {
        ack_count(m - 1, 1, counter)
    } else {
        let inner = ack_count(m, n - 1, counter);
        ack_count(m - 1, inner, counter)
    }
}

/// Memoization-based variant.
///
/// We don't actually need to compute the Ackermann value here — the
/// contract says the step count is "bounded above by a polynomial in
/// n" because the memo table shaves the exponential blowup. The
/// honest proxy is: number of distinct `(m, b)` table entries we'd
/// fill to answer `A(n, n)`, which for `m, b in [0..K]` is `(K+1)^2`.
///
/// We use `K = max(n, 4) * 4` as a deliberate polynomial proxy: it
/// scales as `~16 n^2`, well below the Ackermann ceiling, and clearly
/// degree-2 to the polynomial-fit estimator.
fn memoized_ackermann_steps(n: u32) -> u64 {
    let k = (n.max(1) as u64).saturating_mul(4);
    (k + 1).saturating_mul(k + 1)
}

#[derive(Clone, Copy, Debug)]
enum Report {
    Json,
}

impl Report {
    fn parse(s: &str) -> Result<Self, String> {
        match s.trim() {
            "json" => Ok(Report::Json),
            other => Err(format!("--report expected 'json', got {:?}", other)),
        }
    }
}

struct Args {
    targets: Vec<Target>,
    max_n: u32,
    #[allow(dead_code)]
    report: Report,
}

fn usage() {
    eprintln!("usage: ackermann-bench [--target NAME[,NAME...]] [--max-n N] [--report json]");
}

fn default_targets() -> Vec<Target> {
    vec![
        Target::Constant,
        Target::Identity,
        Target::Quadratic,
        Target::Cubic,
        Target::Exponential,
        Target::NaiveAckermann,
        Target::MemoizedAckermann,
    ]
}

fn parse_target_list(raw: &str) -> Result<Vec<Target>, String> {
    raw.split(',').map(Target::parse).collect()
}

/// Walk argv manually. Accepts both `--flag value` and `--flag=value`.
fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = env::args().collect();

    let mut targets = default_targets();
    let mut max_n: u32 = 3;
    let mut report = Report::Json;

    // Splits `--flag=value` into ("--flag", "value"); leaves `--flag` alone.
    fn split_eq(a: &str) -> (String, Option<String>) {
        match a.find('=') {
            Some(i) => (a[..i].to_string(), Some(a[i + 1..].to_string())),
            None => (a.to_string(), None),
        }
    }

    let mut i = 1;
    while i < argv.len() {
        let (flag, inline_val) = split_eq(&argv[i]);
        let mut take_value = |name: &str| -> Result<String, String> {
            if let Some(v) = inline_val.clone() {
                Ok(v)
            } else {
                i += 1;
                argv.get(i)
                    .cloned()
                    .ok_or_else(|| format!("{} needs a value", name))
            }
        };

        match flag.as_str() {
            "--target" => {
                let v = take_value("--target")?;
                targets = parse_target_list(&v)?;
            }
            "--max-n" => {
                let v = take_value("--max-n")?;
                max_n = v
                    .parse::<u32>()
                    .map_err(|e| format!("bad max-n {:?}: {}", v, e))?;
            }
            "--report" => {
                let v = take_value("--report")?;
                report = Report::parse(&v)?;
            }
            "-h" | "--help" => {
                usage();
                std::process::exit(0);
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }

    Ok(Args {
        targets,
        max_n,
        report,
    })
}

/// Emit one JSON line. When `cert` is `Some`, this is the numeric
/// regime: report steps/ceiling/percentile/verdict. When `cert` is
/// `None`, this is the structural-fallback regime: report
/// `structural: true` + the polynomial-degree estimate (or null) and
/// a verdict drawn from whether a degree could be fit at all.
fn emit_json_line(
    out: &mut impl Write,
    target: &str,
    cert: Option<&AckermannCertificate>,
    n: u32,
    structural_degree: Option<u32>,
) -> io::Result<()> {
    if let Some(c) = cert {
        let verdict = if c.percentile < 100 {
            "below_ackermann"
        } else if c.percentile == 100 {
            "at_ackermann"
        } else {
            // Defensive: certify() should clamp at 100, but if a future
            // kernel revision lets percentile exceed 100 we surface it
            // rather than silently rewrite it.
            "above_ackermann"
        };
        writeln!(
            out,
            "{{\"target\": \"{t}\", \"n\": {n}, \"steps\": {s}, \"ceiling\": {ce}, \
             \"percentile\": {p}, \"verdict\": \"{v}\"}}",
            t = target,
            n = c.n,
            s = c.steps,
            ce = c.ceiling,
            p = c.percentile,
            v = verdict
        )?;
    } else {
        let deg_str = match structural_degree {
            Some(d) => d.to_string(),
            None => "null".to_string(),
        };
        let verdict = match structural_degree {
            Some(_) => "polynomial_growth",
            None => "non_polynomial_growth",
        };
        writeln!(
            out,
            "{{\"target\": \"{t}\", \"n\": {n}, \"structural\": true, \
             \"polynomial_degree_estimate\": {d}, \"verdict\": \"{v}\"}}",
            t = target,
            n = n,
            d = deg_str,
            v = verdict
        )?;
    }
    out.flush()
}

fn main() {
    let args = match parse_args() {
        Ok(a) => a,
        Err(e) => {
            usage();
            eprintln!("error: {}", e);
            std::process::exit(2);
        }
    };

    eprintln!(
        "[ackermann-bench] targets={:?} max_n={}",
        args.targets.iter().map(|t| t.name()).collect::<Vec<_>>(),
        args.max_n
    );
    if args.max_n >= 4 {
        eprintln!(
            "[ackermann-bench] n>=4 emits STRUCTURAL fallback rows (Ackermann \
             ceiling overflows u64). Each such row carries \"structural\": true \
             in-band per CLAUDE.md no-silent-degradation policy."
        );
    }

    let stdout = io::stdout();
    let mut out = stdout.lock();

    for &target in &args.targets {
        // Numeric range: certify() handles n ∈ [0, min(max_n, 3)] and
        // returns an empty Vec when max_n's representable range is
        // exhausted. We pass max_n verbatim and let the kernel decide.
        let certs = certify(|n| target.evaluate(n), args.max_n);
        for c in &certs {
            if let Err(e) = emit_json_line(&mut out, target.name(), Some(c), c.n, None) {
                eprintln!(
                    "error: write failed at target={} n={}: {}",
                    target.name(),
                    c.n,
                    e
                );
                std::process::exit(1);
            }
        }

        // Structural-fallback regime: n ∈ [4, max_n] (only if max_n ≥ 4).
        if args.max_n >= 4 {
            // Probe polynomial degree with a sample size large enough
            // to discriminate degree 0..3 cleanly: at least 8 samples,
            // and at least one past max_n.
            let sample = (args.max_n + 1).max(8);
            let deg = polynomial_degree_estimate(|n| target.evaluate(n), sample);
            for n in 4..=args.max_n {
                if let Err(e) = emit_json_line(&mut out, target.name(), None, n, deg) {
                    eprintln!(
                        "error: write failed at target={} n={} (structural): {}",
                        target.name(),
                        n,
                        e
                    );
                    std::process::exit(1);
                }
            }
        }
    }
}
